{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-three-action-ordering-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的进料流量缺失、分离器定压参数缺失，以及分离器气相出口未连接问题生成候选编辑提案；这些提案均为非执行式 patch，需要确认后才可应用。",
      "issues": [
        {
          "code": "STREAM_SPEC_MISSING",
          "message": "Charge Heater Feed 缺少流量规格，导致进料边界条件不完整。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "feed-71"
          },
          "citations": [
            "diag-2",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "code": "UNIT_PARAMETER_INCOMPLETE",
          "message": "Hot Flash Separator 处于 fixed pressure 模式，但缺少操作压力目标。",
          "severity": "error",
          "target": {
            "type": "unit",
            "id": "separator-7"
          },
          "citations": [
            "diag-3",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "code": "STREAM_DISCONNECTED",
          "message": "Separator Vapor 71 未连接到下游消费者或导出汇，当前拓扑无效。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "separator-vapor-71"
          },
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Charge Heater Feed 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-71"
          },
          "rationale": "诊断直接指出该进料流缺少流量规格。当前文档中该流已有压力和温度规格，但没有流量边界条件；添加占位可让用户补入设计基准，而不擅自假定数值。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "suggested_source": "user_input",
                "note": "请确认并填写 Charge Heater Feed 的流量规格及单位。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1",
            "snapshot-1"
          ],
          "confidence": 0.92
        },
        {
          "action": "candidate_edit",
          "title": "为 Hot Flash Separator 补充定压目标占位",
          "target": {
            "type": "unit",
            "id": "separator-7"
          },
          "rationale": "诊断显示该 FlashDrum 使用 fixed pressure 模式但缺少 operating pressure target。文档中其上游入口流 heater-outlet-71 的 pressure_kpa 为 196，下游 vapor 流现有 pressure_kpa 为 176，但二者不能自动替代设备操作压力；因此仅建议添加待确认的参数占位。",
          "patch": {
            "parameter_placeholders": {
              "operating_pressure_kpa": {
                "required": true,
                "suggested_source": "user_input_or_confirm_from_nearby_stream_specs",
                "note": "请确认 Hot Flash Separator 在 fixed pressure 模式下的操作压力目标。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-2",
            "flowdoc-stream-2",
            "flowdoc-stream-3",
            "snapshot-1"
          ],
          "confidence": 0.86
        },
        {
          "action": "candidate_edit",
          "title": "为 Separator Vapor 71 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "separator-vapor-71"
          },
          "rationale": "诊断指出该气相出口没有任何下游消费者或导出汇，且快照状态为 invalid_topology。由于当前输入没有给出明确的目标单元或导出节点，不能直接重连到具体对象；只能建议添加待确认的连接占位。",
          "patch": {
            "connection_placeholder": {
              "missing_endpoint": "target_unit_id_or_export_sink",
              "required": true,
              "allowed_resolution": [
                "connect_to_existing_downstream_unit",
                "mark_as_export_sink"
              ],
              "note": "请确认 Separator Vapor 71 的下游消费者，或确认其应作为导出/产品边界流。"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-4",
            "flowdoc-stream-3",
            "snapshot-1"
          ],
          "confidence": 0.78
        }
      ],
      "confidence": 0.85
    }
  ]
}
